const pipeline = $('Get Pipeline Data').all();
const wonLost = $('Get Won Lost This Period').first().json;

const totalPipeline = pipeline.reduce((sum, s) => sum + (parseFloat(s.json.total_value) || 0), 0);
const weightedPipeline = pipeline.reduce((sum, s) => sum + (parseFloat(s.json.weighted_value) || 0), 0);
const dealCount = pipeline.reduce((sum, s) => sum + (parseInt(s.json.deal_count) || 0), 0);
const avgDealSize = dealCount > 0 ? totalPipeline / dealCount : 0;
const won = parseFloat(wonLost.won) || 0;
const lost = parseFloat(wonLost.lost) || 0;
const convRate = (won + lost) > 0 ? (won / (won + lost)) * 100 : 0;

const now = new Date();
const weekNum = Math.ceil(((now - new Date(now.getFullYear(), 0, 1)) / 86400000 + 1) / 7);

return [{ json: {
  period_type: 'weekly',
  period_label: `W${weekNum}-${now.getFullYear()}`,
  pipeline_total: totalPipeline.toFixed(2),
  weighted_pipeline: weightedPipeline.toFixed(2),
  won_to_date: won.toFixed(2),
  lost_to_date: lost.toFixed(2),
  deal_count: dealCount,
  avg_deal_size: avgDealSize.toFixed(2),
  conversion_rate: convRate.toFixed(2)
}}];
